"""
MKT Christ Commentary — Revelation chapters 6–11
Run: python3 scripts/zc-christ-revelation-6-11.py

Every verse receives a Christological entry. Key decisions:
- Lamb-as-opener of seals (ch 6): Christ holds executive authority over all historical events;
  the four horsemen operate within his governance, not independently
- "Wrath of the Lamb" (6:16): the paradox that the crucified one is the cosmic judge;
  grace refused becomes the most fearsome judgment
- Sealing of the 144,000 (7:2-8): the seal of God = the Holy Spirit (Eph 1:13; 4:30);
  Judah listed first (not Reuben) = the tribe of Christ reorganizes the census
- "Salvation belongs to our God... and to the Lamb" (7:10): the Lamb receives the
  salvation-cry alongside God — a Christological claim at the highest level
- "Washed robes in the blood of the Lamb" (7:14): the paradox of atonement
- The Lamb as shepherd (7:17): paradox of the slain Lamb becoming the Good Shepherd
- Altar-incense-intercession (8:3-5): Christ's high-priestly intercession (Heb 7:25; 9:24)
  is the NT basis for the incense scene; judgment and intercession from the same altar
- The mighty angel (10:1): face like the sun and rainbow head deliberately echoes 1:16/4:3;
  treated as a Christ-type figure
- Two witnesses (11:3-12): death/resurrection/ascension pattern = explicit typology of Christ
- 11:8 "where their Lord was crucified": the text itself identifies Jerusalem and the cross
- Seventh trumpet (11:15): "the kingdom of our Lord and of his Christ" = the climactic
  enthronement declaration; the already-not-yet tension of the NT resolved
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

REVELATION = {
  "6": {
    "1": '<p>The Lamb opens the first seal, initiating the disclosure of history\'s judgments. The Lamb who was slain (ch 5) — who alone was found worthy to open the scroll — is now the sovereign executor of all that the scroll contains. The crucified one is the cosmic judge: the cross did not diminish Christ\'s authority but established it (Phil 2:9-11). Every seal that follows is opened by the same hand that bore the marks of crucifixion.</p>',
    "2": '<p>The white horse rider who \'came out conquering and to conquer\' is best understood as a Christological figure in light of 19:11-16, where the Rider on the white horse is explicitly Christ — \'Faithful and True.\' The bow without arrows and the crown suggest victory through proclamation rather than military force, consistent with Heb 4:12 (the word of God, sharper than a two-edged sword) and John 16:33 (\'I have overcome the world\'). The word of Christ goes forth to conquer at the opening of history\'s seals.</p>',
    "3": '<p>The Lamb opens the second seal. Every seal opens at Christ\'s initiative; historical events — including geopolitical conflict — operate within his governance. That the Lamb personally opens each seal emphasizes that no historical catastrophe is outside his authority or knowledge. He is Lord even of what appears as chaos.</p>',
    "4": '<p>The red horse rider is \'permitted\' to take peace from the earth — the passive voice signals divine permission. War in history operates within the scope of what Christ allows. Col 1:17 (\'in him all things hold together\') applies even to conflict: the fabric of history coheres in Christ, including its ruptures. The limited fractional measures throughout these chapters show that the judgments are proportioned, not total annihilation.</p>',
    "5": '<p>The Lamb opens the third seal. Famine, like war and conquest, operates within Christ\'s permitted governance of history. The scales in the rider\'s hand evoke economic measurement — the rationing of basic resources. Christ rules not only through abundance (John 6:35: \'whoever comes to me will never go hungry\') but also, in judgment, through measured scarcity.</p>',
    "6": '<p>\'A quart of wheat for a denarius\' — subsistence prices, with luxury items (oil and wine) protected. The voice from \'the midst of the four living creatures\' (near the Lamb\'s throne) limits the famine\'s scope. Christ\'s judgment is measured and proportioned, not indiscriminate. The protection of oil and wine may echo the new covenant provision — the Spirit (symbolized by oil) and the messianic table (wine) are preserved even in judgment.</p>',
    "7": '<p>The Lamb opens the fourth seal. Death and Hades follow the pale rider — but Christ holds the keys of Death and Hades (1:18). He does not open the fourth seal from a distance: even the coming of Death is under his jurisdiction. The authority given to the pale rider (\'authority over a fourth of the earth\') is delegated, bounded by the one who holds the keys.</p>',
    "8": '<p>\'Its rider\'s name was Death, and Hades followed him.\' Christ proclaimed: \'I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live\' (John 11:25). Death is the last enemy (1 Cor 15:26), but it is an enemy already defeated at the cross and resurrection. Here it still operates as an instrument of judgment — the quarter-measure limited by Christ — but its ultimate end is the lake of fire (20:14). Death rules now only within Christ\'s permission and decreed limits.</p>',
    "9": '<p>The fifth seal reveals the souls of the martyrs under the altar — those who died \'for the word of God and for the testimony they had maintained.\' The language of \'testimony\' (<em>martyria</em>) is specifically the testimony of Jesus (1:2, 9; 12:17; 19:10). They died for bearing the witness that Christ himself bore (3:14: \'the faithful witness\'); their martyrdom is participation in his. The altar is the place of sacrifice — echoing the altar at which Christ\'s own blood was the atoning offering.</p>',
    "10": '<p>The martyrs cry: \'O Sovereign Lord, holy and true, how long before you will judge and avenge our blood?\' The titles \'holy and true\' are used of Christ in 3:7. Their blood cries out to the one who bore the marks of crucifixion; Christ\'s blood \'speaks a better word than the blood of Abel\' (Heb 12:24), and the martyrs\' blood is gathered into his. Their cry for justice is addressed to the one who is both their redeemer and the judge — the same person.</p>',
    "11": '<p>White robes are given to each martyr — the robes representing the righteousness of Christ credited to those in him (7:14: \'they have washed their robes and made them white in the blood of the Lamb\'). The command to \'rest a little longer\' echoes the promise to all who die in Christ: \'Blessed are the dead who die in the Lord from now on... they will rest from their labor\' (14:13). The number of martyrs is not yet complete — the church\'s testimony continues.</p>',
    "12": '<p>The sixth seal brings cosmic upheaval — the shaking of sun, moon, stars, and the earth. Heb 12:26-27 applies Hag 2:6 (\'once more I will shake not only the earth but also the heavens\') to the coming of Christ\'s unshakeable kingdom: \'The removing of things that are shaken... in order that the things that cannot be shaken may remain.\' The cosmic signs of the sixth seal herald the approach of the kingdom that Christ is bringing — the old order is being shaken to make way for the new.</p>',
    "13": '<p>The stars fall like figs shaken from a tree in a gale. Isa 34:4 describes this image in the doom of Edom, which Matt 24:29 quotes in connection with the coming of the Son of Man (\'the stars will fall from the sky\' immediately after the tribulation). The dissolution of the starry order is the undoing of the \'rulers\' and \'authorities\' associated with heavenly bodies in ancient cosmology — the principalities and powers that Christ disarmed at the cross (Col 2:15).</p>',
    "14": '<p>The sky vanishing like a rolled-up scroll and mountains and islands removed: Isa 34:4 and Isa 54:10 (\'the mountains may depart and the hills be removed, but my steadfast love will not depart from you\'). The reversal of creation\'s stable order is the harbinger of the new creation (2 Pet 3:10-13; 21:1). Christ\'s resurrection is the firstfruits of this new creation (1 Cor 15:20-23); the shaking of the old order is the birth pangs of what his resurrection inaugurated.</p>',
    "15": '<p>The great ones of the earth — kings, generals, the wealthy, the powerful — hide in caves. The social hierarchy that Rome embodied collapses before \'the face of him who is seated on the throne, and from the wrath of the Lamb.\' Human rank provides no protection before the Lamb\'s judicial authority. Those who trusted in Roman power face the same exposure as the powerless they exploited.</p>',
    "16": '<p>\'Hide us from the face of him who is seated on the throne, and from the wrath of the Lamb.\' The phrase \'wrath of the Lamb\' is the book\'s central paradox: the Lamb, symbol of sacrificial gentleness and substitutionary suffering, is also the source of the most fearsome wrath. Grace refused is the severest judgment. Those who rejected the Lamb\'s offer of his own blood as atonement (5:9-10) now face the Lamb as judge. The same cross that is the door of salvation (John 10:9) is the stone of judgment for those who refuse it (1 Pet 2:8).</p>',
    "17": '<p>\'Who is able to stand?\' — the question echoes Mal 3:2 (\'But who can endure the day of his coming? Who can stand when he appears?\') and Ps 130:3 (\'If you, O LORD, kept a record of sins, who could stand?\'). The answer comes in ch 7: those sealed with the seal of the living God (7:3), those who have washed their robes in the blood of the Lamb (7:14). Christ provides the only standing possible before the Lamb\'s wrath — he absorbed it on the cross so that his own might stand.</p>'
  },
  "7": {
    "1": '<p>Four angels hold back the four winds of judgment — divine restraint preserving space for the sealing of God\'s servants. Before the full force of judgment falls, Christ ensures that his own are marked. This is the Passover pattern (Exod 12:1-13): before the destroying angel moved through Egypt, the blood of the lamb was applied to the doorposts. The Lamb of God ensures that his people are passed over even as judgment descends on the unmarked.</p>',
    "2": '<p>The angel from the east holds \'the seal of the living God.\' In the NT, the seal of God placed on believers is the Holy Spirit: Eph 1:13 (\'you were sealed with the promised Holy Spirit\'); 4:30 (\'do not grieve the Holy Spirit of God, by whom you were sealed for the day of redemption\'); 2 Cor 1:22 (\'God... has... put his Spirit in our hearts as a deposit\'). The sealing of the 144,000 is the Christological sealing that Christ performs through his Spirit — marking his own as his possession.</p>',
    "3": '<p>\'Until we have sealed the servants of our God on their foreheads\' — the forehead-seal contrasts with the mark of the beast (13:16). The contrast is absolute: every person is either sealed by Christ or marked by the beast; there is no neutral ground. The forehead seal echoes Ezek 9:4 (God marking the faithful in Jerusalem before judgment) — the mark protected from the destroying angels then, as the Spirit\'s seal protects from the destroying forces now.</p>',
    "4": '<p>One hundred and forty-four thousand sealed — 12 × 12 × 1,000 = the complete covenant people in symbolic numerology. The twelve tribes of Israel have become 144,000 in Christ: the same covenant community, now constituted by faith in the Lamb. The census pattern follows Num 1-2 (Israel numbered before entering the promised land), but now it is Christ\'s people counted before entering the new creation. The completeness of the number assures the reader: no one of Christ\'s own is lost.</p>',
    "5": '<p>\'From the tribe of Judah, twelve thousand.\' Judah is listed first — not Reuben, the firstborn by birth order (Gen 29:32). Judah heads the list because the Lion of the tribe of Judah (5:5) has reorganized the covenant people by his own victory. The tribe that produced the Messiah takes precedence, and the whole community is reconstituted around him. The census is a Christological one.</p>',
    "6": '<p>Asher, Naphtali, Manasseh sealed. Manasseh\'s inclusion (and the absence of Ephraim and Dan from the standard twelve-tribe list) signals that this is not a literal ethnic census but a theological reconstitution of the covenant community. The completeness (12,000 from every tribe) assures communities facing Roman persecution that God\'s accounting of his people is perfect: not one is overlooked by the Lamb who knows his sheep by name (John 10:3).</p>',
    "7": '<p>Simeon, Levi, Issachar sealed. Levi\'s inclusion is notable: Levi was not given a tribal allotment in Canaan (Josh 13:14) because the LORD was their inheritance. In the eschatological census, Levi is fully included — the priestly tribe that administered the sacrificial system now stands within the community of the new-covenant people, all of whom are priests (1:6; 5:10; 20:6). Christ has dissolved the distinction between the serving tribe and the rest.</p>',
    "8": '<p>Zebulun, Joseph, Benjamin sealed. The list concludes with Benjamin — the tribe of Paul, who considered himself the least of the apostles (1 Cor 15:9) but who was nonetheless sealed and sent. The twelve-thousand-strong completeness from every tribe guarantees that the full extent of God\'s covenant purposes, from every branch of the family of Abraham, is included in the Lamb\'s redemption.</p>',
    "9": '<p>The great multitude from every nation, tribe, people, and language — the fulfillment of the Abrahamic promise (Gen 12:3: \'in you all families of the earth will be blessed\'; Gal 3:8: the gospel announced in advance to Abraham). They stand before \'the throne and the Lamb\' — placing the Lamb in full divine standing alongside God. What began with Abraham\'s faith reaches its completion in the nations standing before the Lamb who redeemed them.</p>',
    "10": '<p>\'Salvation belongs to our God who sits on the throne, and to the Lamb!\' In the OT, salvation belongs to YHWH alone: Ps 3:8; Ps 37:39; Jonah 2:9 (\'Salvation comes from the LORD\'). The great multitude assigns salvation jointly to God and to the Lamb — a Christological claim equivalent to attributing the divine name YHWH to Christ. The Lamb is not an instrument of salvation but its co-source with the Father.</p>',
    "11": '<p>All the angels, elders, and four creatures fall on their faces and worship God. The worship that in 4:10 and 5:14 was offered to both the enthroned one and the Lamb continues unbroken. The Lamb\'s presence with God on the throne is not incidental but the center of the heavenly reality — all of heaven\'s praise orbits the throne on which the Lamb and the Father together receive it.</p>',
    "12": '<p>\'Amen! Blessing and glory and wisdom and thanksgiving and honor and power and might belong to our God forever and ever!\' The sevenfold acclamation here parallels the sevenfold acclamation of the Lamb in 5:12. The same categories of praise offered to the Lamb in ch 5 are offered to God here — the continuity confirms that the Lamb and the Father share the same divine honor.</p>',
    "13": '<p>One of the elders asks John about the great multitude. The elder-as-questioner is the heavenly-guide pattern of apocalyptic literature (Zechariah\'s interpreting angel; Daniel\'s Gabriel). The revelation is structured as a question and answer to draw John — and the reader — into active reception of the truth. Christ used the same method: questions that drew out deeper understanding (John 11:25-26; Matt 16:15: \'But who do you say that I am?\').</p>',
    "14": '<p>\'These are the ones coming out of the great tribulation; they have washed their robes and made them white in the blood of the Lamb.\' The central paradox of Christological soteriology: blood that stains makes white; the atoning death of Christ (1:5: \'freed us from our sins by his blood\'; 5:9: \'with your blood you ransomed people for God\') cleanses what nothing else can purify. The \'washing\' is appropriated through faith — the robes were \'washed,\' not merely splashed.</p>',
    "15": '<p>\'He who sits on the throne will shelter them with his presence.\' The Greek <em>skēnōsei ep\' autous</em> (\'will spread his tent/tabernacle over them\') echoes John 1:14 (the Word \'tabernacled\' among us) and looks forward to 21:3 (\'the dwelling of God is with man\'). The sheltering presence that Christ embodied in his incarnation is here the eschatological promise — the tabernacling of God with his people, mediated through the Lamb who opened the way.</p>',
    "16": '<p>\'They will never hunger or thirst again.\' Christ declared: \'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst\' (John 6:35). The promises he made in his earthly ministry are here the eschatological reality. Isa 49:10 (the servant\'s people will not hunger or thirst) is the prophetic background; Jesus\'s appropriation of these promises in the Gospels makes them Christological. The great multitude lives in the fullness of what Jesus promised the woman at the well (John 4:14).</p>',
    "17": '<p>\'For the Lamb at the center of the throne will be their shepherd and will lead them to springs of living water.\' The paradox of the shepherd-Lamb: the Lamb who was slain (5:6) is the Good Shepherd (John 10:11: \'the good shepherd lays down his life for the sheep\'). The Lamb became the sacrifice to become the shepherd; the slaughter was the path to the pastoral role. He leads to \'springs of living water\' (John 4:10-14; 7:37-38), and God wiping away every tear (Isa 25:8) arrives through the Lamb\'s shepherding of the redeemed.</p>'
  },
  "8": {
    "1": '<p>When the Lamb opens the seventh seal, there is silence in heaven for about half an hour — the reverential hush before the climactic judicial act. The Lamb\'s authority over the seventh seal is total: what he opens, none can close (3:7). The silence is the creation\'s response to the presence of the one who bears both the marks of the cross and the authority of the cosmos — the pregnant pause before the word of Christ\'s judgment is spoken.</p>',
    "2": '<p>Seven angels are given seven trumpets — the instruments of divine proclamation and judgment (Josh 6:1-21: the trumpets at Jericho; 1 Thess 4:16: \'the trumpet call of God\' accompanies Christ\'s return). The seven trumpets proceed from the Lamb\'s opening of the seventh seal — the entire trumpet sequence is Christ\'s executive action in history. The angels are instruments; Christ is the executive authority behind each blast.</p>',
    "3": '<p>The angel at the golden altar with incense — Heb 7:25 (Christ \'always lives to make intercession\' for those who come to God through him) and Heb 9:24 (he \'entered heaven itself, now to appear in the presence of God on our behalf\'). The incense offering before God\'s throne embodies the priestly intercession that the NT identifies with Christ\'s ongoing high-priestly ministry. The prayers of the saints are received through the mediating work of the one who offered himself as the ultimate sacrifice.</p>',
    "4": '<p>The smoke of incense with the prayers of the saints rising before God — Christ\'s intercession carries the prayers of his people to the Father. Rom 8:34 (\'Christ Jesus... is at the right hand of God and is also interceding for us\') and John 17 (the high-priestly prayer) are the Gospel and epistolary background. The martyrs\' cry of \'how long?\' (6:10) is among the prayers rising through this incense — Christ carries their cry to the Father\'s throne.</p>',
    "5": '<p>Fire from the altar hurled to the earth — the altar that received the saints\' prayers and Christ\'s intercession now becomes the source of divine judgment. The intercessory altar and the judicial altar are the same: Christ\'s priestly intercession and his judicial authority are unified in the one mediator (1 Tim 2:5). The prayers for justice (6:10) answered in judgment (fire on the earth) show that intercession and judgment are both Christ\'s to exercise.</p>',
    "6": '<p>The seven angels prepare to sound their trumpets — the entire trumpet sequence proceeds from the Lamb\'s seal-opening (v. 1) and the altar-prayer dynamic (vv. 3-5). The full sequence of historical judgments is under Christ\'s executive authority. No trumpet sounds without his governance; no judgment falls outside the scope of his opened scroll. The preparatory pause emphasizes the deliberateness and authority of what follows.</p>',
    "7": '<p>The first trumpet — hail and fire mixed with blood hurled onto the earth. This is the seventh plague of Egypt (Exod 9:13-35) redeployed as an eschatological Exodus judgment. Christ executes the new-Exodus judgment on the anti-Exodus empire (Rome = the new Egypt in Rev 11:8). As Moses mediated the Exodus plagues against Egypt that refused to release God\'s people, so Christ mediates the eschatological plagues against Rome that refuses to release the church.</p>',
    "8": '<p>The second trumpet — a blazing mountain thrown into the sea. Jer 51:25 pronounces doom on Babylon as \'a destroying mountain\' that God will make \'a burnt-out mountain\' — applied now to Rome as the new Babylon. \'A third of the sea turned to blood\' echoes the first Exodus plague (Exod 7:20-21). The fractional \'third\' measure throughout the trumpet sequence demonstrates that Christ\'s judgment has proportionality: severe but measured, not indiscriminate destruction.</p>',
    "9": '<p>A third of the sea creatures died and a third of the ships destroyed. The judgment falls on Rome\'s commercial empire — its seaborne trade network (the merchants, sea captains, and sailors who mourned Rome\'s fall in 18:17-19). Christ\'s judgment is targeted: the commercial system that exploited the nations and fed on their labor is the specific object of the sea-judgment.</p>',
    "10": '<p>The third trumpet — a great star blazing like a torch falls on the rivers and springs, poisoning them. Jer 9:15 (God will make the people \'eat bitter food and drink poisoned water\' as judgment for apostasy) is the background. Christ promised living water to all who come to him (John 4:10-14; 7:37-38); the poisoning of earthly waters in judgment contrasts with the unpoisoned living water he provides. Those who rejected the water of life now drink from waters made bitter by judgment.</p>',
    "11": '<p>The star named Wormwood causes many to die from the bitter waters. John 6:53-58: Jesus declared that those who do not eat his flesh and drink his blood have no life in them; the bitter waters of judgment are the reversal of the cup of salvation (Ps 116:13) that Christ offers. The bitter cup that he drank on the cross (Mark 14:36: \'take this cup from me\') redeems those who would otherwise drink only from bitter waters.</p>',
    "12": '<p>The fourth trumpet — a third of the sun, moon, and stars darkened. Amos 8:9; Joel 2:31; and Matt 24:29 (Jesus quoting these cosmic signs in connection with the coming of the Son of Man). The darkening of the lights echoes John 1:5 (the light shines in the darkness) — Christ is the light that cannot ultimately be extinguished; these are penultimate darkenings, not the final light-out. \'I am the light of the world\' (John 8:12) remains true even when the created lights are darkened.</p>',
    "13": '<p>The eagle flying in midheaven crying \'Woe, woe, woe\' — the three woes are the anti-beatitudes: instead of \'blessed\' there is \'woe.\' Christ pronounced beatitudes on the poor in spirit, the mourning, the meek (Matt 5:3-12); he also pronounced woes on those who rejected his kingdom (Matt 23:13-36). The eagle\'s cry signals that what follows surpasses what came before — the remaining trumpets are directed specifically at those who refuse repentance.</p>'
  },
  "9": {
    "1": '<p>The fifth angel sounds; a fallen star is given the key to the bottomless pit. Christ holds the keys of Death and Hades (1:18) and the key of David (3:7). The key given to this fallen star is delegated authority — the Abyss is not opened by any autonomous power but by divine permission under Christ\'s governance. The one who was given all authority in heaven and on earth (Matt 28:18) permits the opening of the Abyss for the purpose of his judicial plans.</p>',
    "2": '<p>Smoke pours from the Abyss darkening the sun and air — demonic forces can only operate by obscuring what Christ illumines. Christ is the \'light of the world\' (John 8:12; 9:5); the sun\'s darkening is the temporary obscuring of created light by unleashed demonic darkness. The darkness cannot ultimately overcome the light (John 1:5), but during the permitted period of demonic activity the light\'s fullness is dimmed — not extinguished.</p>',
    "3": '<p>Demonic locusts emerge from the smoke — the eighth plague of Egypt (Exod 10:12-20) redeployed as an eschatological judgment. Christ executes a new-Exodus reckoning through the permitted activity of demonic forces. The locusts\' scorpion-power is a limited, constrained power — like the Satan of Job 1-2, they afflict within the limits set by the one who holds the keys to their prison.</p>',
    "4": '<p>The locusts cannot harm those with the seal of God — the Christological seal of the Holy Spirit (7:2-3; Eph 1:13; 4:30) protects Christ\'s own from demonic assault. This is the Passover principle applied eschatologically: the blood of the Lamb (the atoning death of Christ) marks his people as his possession, and the destroying power must pass over them (Exod 12:13). Christ\'s cross is the boundary that demonic power cannot cross for those who are in him.</p>',
    "5": '<p>The locusts can torment but not kill, for five months — the limit of demonic power is set by divine decree. Job 1:12 (\'on the man himself do not lay a finger\') is the prototype: Satan afflicts within the limits Christ sets. The \'five months\' is the life-span of a locust — the judgment is seasonal, bounded, not eternal. Christ\'s governance of demonic activity is precise.</p>',
    "6": '<p>\'People will seek death and not find it; they will long to die, and death will flee from them.\' Christ promised: \'I came that they may have life and have it abundantly\' (John 10:10). The demonic torment produces the opposite — desperate desire for death, the complete inversion of the life Christ offers. Death itself, which Christ holds (1:18), refuses to grant the merciful release its seekers desperately want. This is the eschatological consequence of rejecting the gift of life that Christ alone provides.</p>',
    "7": '<p>The locusts\' appearance — like war horses with gold crowns, human faces, and lion teeth — creates a grotesque parody of the divine throne-room. The four living creatures of ch 4 represent the fullness of creation in worship before God; these demonic creatures parody that fullness in destruction. The demonic always imitates the divine but in distorted, death-dealing form — Christ\'s true image (the firstborn of all creation, Col 1:15) is counterfeited by the demonic, which imitates without creating.</p>',
    "8": '<p>\'They had hair like women\'s hair and teeth like lions\' teeth.\' The composite description defies natural category — these are creatures belonging to no created order but to the chaos that Christ has conquered. At the cross, Christ \'disarmed the rulers and authorities and put them to open shame, by triumphing over them in him\' (Col 2:15). The locust-army\'s terrifying appearance is the appearance of a defeated power — frightening precisely because it knows its time is limited (12:12).</p>',
    "9": '<p>Breastplates like iron, wings like charging chariots — the imagery of overwhelming force against which the communities of the seven cities are humanly powerless. But Christ\'s promise to his church is not military capacity but sealing and protection: \'Fear not, for I have overcome the world\' (John 16:33). The iron breastplates of the demonic locusts are answered not by the church\'s armor but by the Lamb\'s blood, which has already won the definitive battle.</p>',
    "10": '<p>Scorpion-tails with stingers causing five months of torment — the bounded power of the demonic again emphasized. Luke 10:19: Jesus said \'I have given you authority to tread on serpents and scorpions, and over all the power of the enemy; and nothing shall hurt you.\' The authority Christ grants to his messengers to tread on scorpions exceeds the scorpion-power of the locusts. The demonic authority is over-matched by the Christological authority delegated to the church.</p>',
    "11": '<p>Their king is the angel of the Abyss — Abaddon in Hebrew, Apollyon in Greek (the Destroyer). Christ is the Prince of Peace (Isa 9:6) and the one who \'destroys the works of the devil\' (1 John 3:8). The Destroyer-king parodies and inverts the Prince of Peace: the satanic kingdom\'s leadership is defined by destruction; Christ\'s kingdom by the creation and sustaining of life. Apollyon is a created angel operating in the Abyss that Christ holds the key to open and close.</p>',
    "12": '<p>\'The first woe has passed; behold, two woes are still to come.\' The staged structure of Christ\'s judgment: the woes escalate but are not simultaneous. Divine patience is built into the structure — there are pauses between the seals, between the trumpets, between the bowls. Each stage gives opportunity for repentance (vv. 20-21). Christ\'s judgment is not hasty; the pauses reflect the longsuffering of the one who is \'not wishing that any should perish\' (2 Pet 3:9).</p>',
    "13": '<p>The sixth angel sounds; a voice from the four horns of the golden altar commands the release of four bound angels. The voice comes from the altar — the same altar of incense (8:3-5) where the prayers of the saints were offered. Judgment proceeds from the same place as intercession: the altar that held the martyrs\' prayers (6:9) and the saints\' intercessions (8:3) now issues the command for the next wave of judgment. Christ\'s intercession and his judgment are inseparable functions of the same high-priestly authority.</p>',
    "14": '<p>\'Release the four angels who are bound at the great river Euphrates.\' The \'bound\' angels are constrained by divine decree — they operate only at the appointed time. The language of \'bound and released\' echoes Jesus\'s teaching on binding and loosing (Matt 16:19; 18:18): what is bound or released in the divine plan is under the authority of the one who holds the keys to the kingdom.</p>',
    "15": '<p>\'The four angels who had been prepared for this very hour, day, month, and year.\' The divine precision — hour, day, month, year — is the precision of sovereign providence. Christ said: \'It is not for you to know times or seasons that the Father has fixed by his own authority\' (Acts 1:7); but those times and seasons are fixed. The judgment at the exact appointed moment demonstrates that history\'s events are under Christ\'s governance at the level of individual hours.</p>',
    "16": '<p>Two hundred million mounted troops — the numerical scale staggers the imagination but does not escape Christ\'s governance. He who is \'ruler of the kings of the earth\' (1:5) rules armies of this magnitude. The scale emphasizes the cosmic dimension of the judgment; the limitation to \'kill a third of humanity\' (v. 15) emphasizes that even two hundred million troops operate within divinely set bounds. Magnitude does not equal autonomy from Christ\'s sovereignty.</p>',
    "17": '<p>The horses breathe fire, smoke, and sulfur — the plagues of Sodom (Gen 19:24: fire and sulfur) and the lake of fire (20:10) are anticipated in miniature. The demonic cavalry employs the instruments of final judgment in a penultimate form — warning and foretaste of what awaits those who do not repent. Christ\'s parables described similar warnings (Matt 13:40-42: the fiery furnace); these trumpet plagues are parables acted out on a cosmic scale.</p>',
    "18": '<p>A third of humanity killed by the three plagues — fire, smoke, sulfur. The fractional measure continues the pattern of proportioned, not total, judgment. These judgments are warnings before the final reckoning (which comes with the bowls of wrath in chs. 15-16). Christ\'s judgment is pedagogical as well as penal: the escalation from seals to trumpets to bowls mirrors the escalation of warnings before the final settling of accounts.</p>',
    "19": '<p>The horses\' mouths and tails both cause harm — the dual weapon echoes the serpent\'s tail (12:4) and the locusts\' tails (9:10). The demonic powers work through speech (lies from the mouth, John 8:44: the devil is the father of lies) and through historical action (the tail, representing deceptions that still harm). Christ defeats both dimensions: his word (John 8:32: \'the truth will set you free\') and his historical act of the cross answer the demonic mouth and tail.</p>',
    "20": '<p>\'The rest of mankind did not repent of the works of their hands and stop worshipping demons.\' The trumpet judgments — like the Exodus plagues that demanded Pharaoh release God\'s people — aimed to call to repentance. The response is hardness. The idols of gold, silver, bronze, stone, and wood (Ps 115:4-8; Dan 5:23) cannot see, hear, or walk — yet they receive worship while the living God is ignored. The refusal to repent after such judgments underscores that judgment alone cannot produce what Christ\'s atonement is uniquely able to produce: genuine transformation of the heart (2 Cor 7:10).</p>',
    "21": '<p>\'They did not repent of their murders, their sorceries, their sexual immorality, or their thefts.\' The four specific sins cluster around the pagan religious and commercial practices of the seven-cities culture: sorcery (<em>pharmakeia</em>) common in temple contexts; sexual immorality integral to temple cult and guild banquets; murder encompassing the execution of believers; theft naming economic exploitation. The repeated absence of repentance demonstrates that judgment alone cannot produce what Christ\'s cross uniquely accomplishes: the redemption that calls the heart to genuine repentance.</p>'
  },
  "10": {
    "1": '<p>A mighty angel descends wrapped in cloud, with a rainbow above his head, face like the sun, legs like pillars of fire. The description deliberately echoes Christ\'s appearance in 1:15-16 (feet like burnished bronze, face like the sun) and the divine throne\'s rainbow (4:3). Many interpreters identify this figure as Christ himself — the pre-incarnate Word appearing in angelic form, as in the OT theophanies (the angel of the LORD in Gen 16:7-13; Exod 3:2-6). Whether identified as Christ or as a supreme Christ-type angel, the figure bears the marks of divine-Christological authority.</p>',
    "2": '<p>The little scroll lying open in his hand — in contrast to the sealed scroll of ch 5 that only the Lamb could open, this scroll is already open. What the Lamb opened (5:9) is now disclosed to John for proclamation. The right foot on the sea and left foot on the land signals cosmic lordship: Christ\'s word and authority extends over the totality of the created order (Matt 28:18: \'All authority in heaven and on earth has been given to me\').</p>',
    "3": '<p>The voice of the mighty angel \'like the roar of a lion\' — Christ is the Lion of the tribe of Judah (5:5). The lion\'s roar is the prophetic call (Amos 3:8: \'The lion has roared — who will not fear? The Sovereign LORD has spoken — who can but prophesy?\'). The seven thunders that respond are the fullness of divine speech — seven indicating completeness. The word of Christ, when spoken, fills the cosmos with its response.</p>',
    "4": '<p>The seven thunders speak but their words are sealed — not everything is disclosed even in the Christological revelation of Revelation. Christ modeled this: \'I have much more to say to you, more than you can now bear\' (John 16:12); \'about that day or hour no one knows, not even the angels in heaven, nor the Son, but only the Father\' (Matt 24:36). Divine revelation has its own timetable; what is sealed by divine authority remains sealed until its appointed time.</p>',
    "5": '<p>The mighty angel raises his right hand toward heaven — the oath posture of Dan 12:7, where \'the man clothed in linen\' (an OT Christ-type figure) raised his hands and swore an oath by the eternal God. The oath is addressed to the Creator God — even the Christ-type figure swears by the Father, consistent with the Son\'s economic submission to the Father within the Trinity (John 5:30; 1 Cor 15:28).</p>',
    "6": '<p>\'There will be no more delay.\' The martyrs\' cry of \'how long?\' (6:10) is answered: the time of waiting is ending. Christ promised: \'Yes, I am coming soon\' (22:20); here the angel announces that the mystery of God will be fulfilled at the seventh trumpet\'s sound. The Creator God by whom the oath is sworn is the one in whom Christ\'s authority is grounded — the triune God\'s commitment to finish what he started in creation and redemption is the ground of the \'no more delay\' announcement.</p>',
    "7": '<p>\'The mystery of God will be fulfilled, just as he announced to his servants the prophets.\' The mystery of God is the gospel — Rom 16:25-26 (\'the revelation of the mystery hidden for long ages past, now revealed and made known through the prophetic writings, so that all the Gentiles might believe and obey\'); Eph 3:4-6 (\'the mystery of Christ... that through the gospel the Gentiles are heirs together with Israel\'). The seventh trumpet\'s announcement (11:15: \'the kingdom of the world has become the kingdom of our Lord and of his Christ\') is the fulfillment of this mystery.</p>',
    "8": '<p>The heavenly voice commands John to take the little scroll from the mighty angel — the prophetic commission requires active appropriation of the word. John is not passively handed revelation; he is sent to take it. This pattern echoes the prophetic calls of Isaiah (Isa 6:8-9), Jeremiah (Jer 1:9-10: words put in his mouth), and Ezekiel (Ezek 2:8-3:3: the scroll given to eat). Christ commissions his prophets in continuity with the OT prophetic tradition.</p>',
    "9": '<p>John is told: \'Take it and eat it. It will make your stomach bitter, but in your mouth it will be sweet as honey.\' Ezekiel ate the scroll (Ezek 2:8-3:3: \'it tasted as sweet as honey\'); Jeremiah found God\'s words to be his joy and heart\'s delight (Jer 15:16) but also found them bringing reproach. The sweetness and bitterness of Christ\'s word is its dual character: the gospel is sweet to those who receive it (eternal life) and bitter in its implications (the judgment of all who reject it).</p>',
    "10": '<p>John ate the scroll — sweet in his mouth but bitter in his stomach. The prophetic experience of receiving divine revelation involves both dimensions. Christ himself experienced this bitterness: he took the cup of God\'s wrath (Mark 14:36: \'take this cup from me\') and drank it on behalf of others, so that those who receive his word might ultimately have only sweetness. The bitterness of prophetic proclamation participates in the bitterness of the cross.</p>',
    "11": '<p>\'You must prophesy again about many peoples, nations, languages, and kings.\' The prophetic recommissioning echoes Jeremiah (Jer 1:10: \'over nations and over kingdoms\') and the Great Commission (Matt 28:18-20: \'all nations\'; Acts 1:8: \'to the ends of the earth\'). Christ commissions his witnesses to the full breadth of the nations. The recommissioning after the bitter-sweet experience ensures that the difficulty of prophetic ministry does not silence the proclamation.</p>'
  },
  "11": {
    "1": '<p>John is given a measuring rod and told to measure the temple — Ezek 40-48 provides the background (the prophet measuring the restored temple in a vision of eschatological restoration). Zech 2:1-5 (an angel measuring Jerusalem, after which God promises to be a wall of fire around it) shows the preserving significance of the measuring act. The temple measured is the community of Christ: \'you yourselves are God\'s temple and God\'s Spirit dwells in your midst\' (1 Cor 3:16). Christ\'s people are the living temple that God preserves through tribulation.</p>',
    "2": '<p>The outer court excluded and given to the nations to trample for forty-two months — the distinction between the measured (preserved) inner sanctuary and the trampled outer court reflects the church\'s experience: external persecution (the nations trample what is visible), while the inner reality (the living relationship with God) is inviolable. Christ\'s promise (Matt 16:18: \'the gates of Hades will not overcome it\') is the ground of the inner sanctuary\'s protection even when the outer court is trampled.</p>',
    "3": '<p>\'I will give authority to my two witnesses, and they will prophesy for 1,260 days.\' The \'I\' is Christ speaking — the one who gave authority to his disciples (Luke 9:1; 10:19; Matt 28:18-20) gives authority to the end-time witnesses. The 1,260 days (= 42 months = time, times, half a time) is the tribulation period of Daniel (Dan 7:25; 12:7) — the bounded period of witness before the end. Christ commissions his witnesses for the full duration of the tribulation, not for a shortened comfortable period.</p>',
    "4": '<p>\'These are the two olive trees and the two lampstands that stand before the Lord of the earth.\' In Zech 4:2-14, the two olive trees supply oil to the menorah through two golden pipes — they are the two anointed ones who stand before the Lord of all the earth. The olive oil is the Spirit; Christ is the anointed one (<em>christos</em> = anointed) who supplies the Spirit to his church\'s lampstands. The witnesses\' prophetic power flows from Christ\'s anointing, not from their own capacity.</p>',
    "5": '<p>Fire from the mouths of the witnesses devours their enemies — Elijah called down fire from heaven (2 Kgs 1:10-12); Jeremiah was told \'I will make my words in your mouth a fire\' (Jer 5:14). The \'fire from the mouth\' is the prophetic word of judgment that Christ spoke to the churches in chs. 2-3 (the sword from his mouth, 2:16). The witnesses wield Christ\'s word, which is the fire that either purifies or judges those who hear it.</p>',
    "6": '<p>Power to shut the sky (Elijah typology, 1 Kgs 17:1) and to turn water to blood and strike the earth with every plague (Moses typology, Exod 7-12) — the witnesses bear the authority of the great OT prophets. At the Transfiguration, Moses and Elijah appeared with Jesus (Matt 17:3; Luke 9:30-31), discussing his coming \'exodus\' (Luke 9:31: his departure, i.e., his death and resurrection). The two witnesses embody the witness of Moses and Elijah — the Law and the Prophets — fulfilled in and empowered by the one who stood between them.</p>',
    "7": '<p>\'When they have completed their testimony, the beast kills them.\' The key phrase: \'when they have completed their testimony.\' The beast\'s power is limited to the period after the witnesses\' commission is fulfilled. Christ himself said \'no one takes my life from me, but I lay it down of my own accord\' (John 10:18); his death came only when his hour had come (John 13:1; 17:1). The witnesses\' deaths are similarly within divine control: they can only be killed after finishing what they were commissioned to do. This is completion, not defeat.</p>',
    "8": '<p>\'Their bodies will lie in the public square of the great city that is figuratively called Sodom and Egypt — the city where their Lord was crucified.\' The text itself identifies the city: \'where their Lord was crucified\' = Jerusalem, the city of Jesus\'s death. The witnesses die where Jesus died; their death is participation in his crucifixion (2 Tim 2:11-12: \'if we died with him, we will also live with him\'). The figural identifications (Sodom for wickedness, Egypt for oppression) apply to Jerusalem as it had become — the city that crucified its Lord becomes the type of all anti-God power.</p>',
    "9": '<p>For three and a half days, people from every people, tribe, language, and nation stare at the bodies — an unholy Pentecost in reverse: where the Spirit gathered the nations to understand God\'s word (Acts 2:5-11), here the nations gather to gloat over its silencing. The three-and-a-half-day period deliberately mirrors the three days of Christ\'s death: the witnesses lie \'dead\' as Christ lay dead, awaiting the same reversal.</p>',
    "10": '<p>\'The inhabitants of the earth will gloat over them, celebrate, and exchange gifts with one another.\' The world\'s celebration echoes the response to Christ\'s crucifixion: the soldiers cast lots for his garments (John 19:23-24), the crowd mocked (Luke 23:35-37), the rulers sneered. But the celebration of the cross was short-lived — the third day upended everything. The witnesses\' murderers celebrate as the crowd celebrated the crucifixion, and for the same duration: a moment before the resurrection.</p>',
    "11": '<p>\'The breath of life from God entered them, and they stood on their feet.\' The resurrection of the witnesses after three and a half days directly echoes Christ\'s resurrection (1 Cor 15:4: \'he was raised on the third day\'). The Greek phrase \'breath of life from God\' (<em>pneuma zōēs ek tou Theou</em>) echoes Gen 2:7 (God breathing life into Adam) and Ezek 37:10 (the valley of dry bones). The witnesses\' resurrection participates in and demonstrates the power of Christ\'s own resurrection — the firstfruits of those who have fallen asleep (1 Cor 15:20).</p>',
    "12": '<p>\'Come up here! And they went up to heaven in a cloud while their enemies looked on.\' The ascension of the witnesses (taken up in a cloud as Christ was taken up in a cloud, Acts 1:9) completes the death-resurrection-ascension pattern. Their enemies watch as Christ\'s disciples watched his ascension (Acts 1:10-11). The public nature of the vindication — \'while their enemies looked on\' — fulfills the promise of ultimate vindication of all who witness for Christ.</p>',
    "13": '<p>The earthquake and the survivors \'gave glory to the God of heaven.\' The resurrection-ascension of the witnesses produces what the trumpet plagues (9:20-21) could not: a response of glorifying God. This is the evangelical power of the resurrection witness — Christ\'s resurrection was the turning point for the disciples (John 20:28: Thomas\'s \'My Lord and my God!\'); the witnesses\' resurrection-ascension produces a similar turning point for some who witness it. The resurrection proclamation achieves what judgment warnings cannot.</p>',
    "14": '<p>\'The second woe has passed; the third woe is coming soon.\' The narrative marker after the witnesses\' ministry is complete signals that their testimony was the content of the second woe — the church\'s prophetic witness, ending in death and resurrection, is part of the divine judgment sequence. The third woe (the seventh trumpet, v. 15) is the immediate culmination. The witnesses\' death and resurrection are not a detour from God\'s judicial plan but integral to it.</p>',
    "15": '<p>\'The kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever.\' This is the climactic declaration of Revelation\'s central message. \'His Christ\' (<em>tou Christou autou</em>) — the genitive identifies Jesus as the Messiah of the LORD, the anointed one of Ps 2:2, 6 (\'I have set my King on Zion, my holy mountain\'). The kingdom inaugurated at Christ\'s first coming (Matt 4:17: \'the kingdom of heaven has come near\'), executed through the seals and trumpets, and announced through the witnesses is here proclaimed as finally and fully arrived. The eternal reign of \'his Christ\' is the telos of all history.</p>',
    "16": '<p>The twenty-four elders fall on their faces and worship God. Their prostration mirrors their prostration in 4:10 and 5:8 — the elders perpetually acknowledge that all authority is derivative and that ultimate worship belongs to the one on the throne. The \'Lord God Almighty\' they thank is the one who shares the throne with the Lamb (3:21; 22:1, 3): their thanksgiving is for the reign that is both the Father\'s and Christ\'s, inseparably.</p>',
    "17": '<p>\'We give you thanks, Lord God Almighty, because you have taken your great power and have begun to reign.\' The aorist \'you have taken your great power and have begun to reign\' (<em>ebasileusas</em>) is the enthronement proclamation — not that God\'s sovereignty newly arrived, but that it has now been fully manifested in history. The same aorist appears in 19:6. Christ\'s kingdom was inaugurated at the incarnation, executed at the cross, and is here proclaimed as having fully come — the already-not-yet tension of the NT resolved in the seventh trumpet\'s announcement.</p>',
    "18": '<p>\'The time has come for... rewarding your servants the prophets and your holy people.\' The martyrs who cried \'how long?\' (6:10) receive the answer: the time has come for their vindication. Christ is the judge who rewards his servants (Matt 25:21: \'well done, good and faithful servant\'; 2 Tim 4:8: \'a crown of righteousness for all who have longed for his appearing\'). \'Destroying those who destroy the earth\' — the destroyer (Apollyon, 9:11) is destroyed by the one who is life itself (John 14:6). Destruction is the final enemy of the one who came to give abundant life.</p>',
    "19": '<p>God\'s temple in heaven opened; the ark of his covenant visible. The ark of the covenant was the footstool of God\'s throne (1 Chr 28:2) and the symbol of his covenant presence — lost before the Babylonian exile (or hidden by Jeremiah, 2 Macc 2:4-8). Its appearance in the heavenly temple signals the fulfillment of the new covenant: Heb 8:6 (Christ is the mediator of a better covenant); 9:11-12 (Christ entered the greater and more perfect tabernacle). The ark that pointed to the presence of God in Israel is now fully revealed — because the new covenant, sealed in Christ\'s blood (Luke 22:20), has fulfilled what the ark represented. The Sinai theophany formula (lightning, thunder, earthquake) announces the covenant\'s climactic arrival.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'revelation')
    merge_comm(existing, REVELATION)
    save_comm('mkt-christ', 'revelation', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / 'revelation.json').read_text())
    all_ok = True
    for ch in range(6, 12):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = sorted(il_vv - out_vv, key=int)
        if missing:
            print(f'  ch{ch}: MISSING {missing}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(out_vv)} verses) ✓')
    if all_ok:
        print('  All chapters complete ✓')

if __name__ == '__main__':
    main()
